import{_ as t,o as a,c as o,a0 as n}from"./chunks/framework.MtcpQdzb.js";const h=JSON.parse('{"title":"The Algebra of Me","description":"","frontmatter":{},"headers":[],"relativePath":"Algebra-of-Me.md","filePath":"Algebra-of-Me.md"}'),r={name:"Algebra-of-Me.md"};function s(i,e,l,g,c,p){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="the-algebra-of-me" tabindex="-1">The Algebra of Me <a class="header-anchor" href="#the-algebra-of-me" aria-label="Permalink to &quot;The Algebra of Me&quot;">‚Äã</a></h1><p>Let us define the universe of the system:</p><blockquote><p><strong>ùïå =</strong> the set of all possible namespaces. <strong>A namespace</strong> is a composite structure: <strong>N = (domain, port)</strong></p></blockquote><p>Each component may be present or absent.</p><h2 id="base-rule-more-specific-‚áí-subset" tabindex="-1">Base Rule: &quot;More specific ‚áí Subset&quot; <a class="header-anchor" href="#base-rule-more-specific-‚áí-subset" aria-label="Permalink to &quot;Base Rule: &quot;More specific ‚áí Subset&quot;&quot;">‚Äã</a></h2><p>When additional components are introduced (subdomain, port, path), the covered region becomes smaller.</p><ul><li><strong>cleaker.me</strong> contains <strong>cleaker.me:8161</strong></li><li><strong>cleaker.me</strong> contains <strong>jabellae.cleaker.me</strong></li><li><strong>jabellae.cleaker.me</strong> contains <strong>jabellae.cleaker.me/board</strong></li></ul><p>Formally: if <strong>A</strong> is less specific than <strong>B</strong>, then <strong>B ‚äÜ A</strong>.</p><h2 id="a0-‚Äî-namespace-as-region" tabindex="-1">A0 ‚Äî Namespace as Region <a class="header-anchor" href="#a0-‚Äî-namespace-as-region" aria-label="Permalink to &quot;A0 ‚Äî Namespace as Region&quot;">‚Äã</a></h2><p>A namespace <strong>N</strong> is a region defined by a set of coordinates:</p><p><strong>N = { domain, port?, path?, subdomain?, ‚Ä¶ }</strong></p><p>There exists a refinement operator (<strong>‚äë</strong>) such that: if <strong>B</strong> adds coordinates to <strong>A</strong>, then <strong>B ‚äë A</strong> and <strong>B ‚äÜ A</strong>.</p><h2 id="a1-‚Äî-relation-as-function" tabindex="-1">A1 ‚Äî Relation as Function <a class="header-anchor" href="#a1-‚Äî-relation-as-function" aria-label="Permalink to &quot;A1 ‚Äî Relation as Function&quot;">‚Äã</a></h2><p>A relation <strong>R</strong> is a function that maps a viewer namespace to a target namespace:</p><p><strong>R : N_viewer ‚Üí N_target</strong></p><h2 id="a2-‚Äî-relation-refinement" tabindex="-1">A2 ‚Äî Relation Refinement <a class="header-anchor" href="#a2-‚Äî-relation-refinement" aria-label="Permalink to &quot;A2 ‚Äî Relation Refinement&quot;">‚Äã</a></h2><p>A relation <strong>R_B</strong> refines <strong>R_A</strong> if for all viewer namespaces, the target of <strong>R_B</strong> is more specific than that of <strong>R_A</strong>.</p><h2 id="a3-‚Äî-relation-composition" tabindex="-1">A3 ‚Äî Relation Composition <a class="header-anchor" href="#a3-‚Äî-relation-composition" aria-label="Permalink to &quot;A3 ‚Äî Relation Composition&quot;">‚Äã</a></h2><p>Given <strong>R_A : N_viewer ‚Üí N_intermediate</strong> and <strong>R_B : N_intermediate ‚Üí N_target</strong>, their composition is:</p><p><strong>R_C(N_viewer) = R_B(R_A(N_viewer))</strong></p><h2 id="a4-‚Äî-identity-relation" tabindex="-1">A4 ‚Äî Identity Relation <a class="header-anchor" href="#a4-‚Äî-identity-relation" aria-label="Permalink to &quot;A4 ‚Äî Identity Relation&quot;">‚Äã</a></h2><p>The identity relation <strong>I</strong> maps any viewer namespace to itself:</p><p><strong>I(N_viewer) = N_viewer</strong></p><h2 id="a5-‚Äî-existence-relation" tabindex="-1">A5 ‚Äî Existence Relation <a class="header-anchor" href="#a5-‚Äî-existence-relation" aria-label="Permalink to &quot;A5 ‚Äî Existence Relation&quot;">‚Äã</a></h2><p>An existence relation <strong>E</strong> maps any viewer namespace to a base existence namespace:</p><p><strong>E(N_viewer) = N_existence</strong></p><h2 id="a6-‚Äî-semantic-to-routing-resolver" tabindex="-1">A6 ‚Äî Semantic-to-Routing Resolver <a class="header-anchor" href="#a6-‚Äî-semantic-to-routing-resolver" aria-label="Permalink to &quot;A6 ‚Äî Semantic-to-Routing Resolver&quot;">‚Äã</a></h2><p>The <strong>.me</strong> language expresses <strong>semantic paths</strong>; Cleaker resolves them into <strong>routing targets</strong>.</p><ul><li><strong>Semantic (.me):</strong> <code>cleaker.me/@username/device/suiGNMacBookAir/PORT/profile</code></li><li><strong>Routing (cleaker):</strong> <code>username.cleaker.me:suiGNMacBookAir:8161/profile</code></li></ul><p>Interpretation:</p><ul><li><strong>.me</strong> defines the meaning (device, PORT, namespace, identity).</li><li><strong>cleaker</strong> performs the resolution (semantics ‚Üí routing).</li><li><strong>monad.ai</strong> is the surface.</li></ul><p>This preserves a clean separation: <strong>language (meaning)</strong> ‚Üí <strong>dictionary (resolver)</strong> ‚Üí <strong>storage (ledger)</strong>.</p>',32)])])}const d=t(r,[["render",s]]);export{h as __pageData,d as default};
